import { createAuthPlugin } from "@better-auth-ui/core"
import {
  multiSessionPlugin as coreMultiSessionPlugin,
  type MultiSessionPluginOptions
} from "@better-auth-ui/core/plugins/multi-session"
import { ManageAccounts } from "@/components/auth/multi-session/manage-accounts"
import { SwitchAccountSubmenu } from "@/components/auth/multi-session/switch-account-submenu"

export const multiSessionPlugin = createAuthPlugin(
  coreMultiSessionPlugin.id,
  (options: MultiSessionPluginOptions = {}) => {
    const core = coreMultiSessionPlugin(options)

    return {
      ...core,
      accountCards: [ManageAccounts],
      userMenuItems: [SwitchAccountSubmenu]
    }
  }
)

import type { MultiSessionAuthClient } from "@better-auth-ui/core/plugins/multi-session"
import {
  multiSessionPlugin as coreMultiSessionPlugin,
  type MultiSessionLocalization,
  multiSessionLocalization
} from "@better-auth-ui/core/plugins/multi-session"
import { useAuth, useSession } from "@better-auth-ui/solid"
import {
  useListDeviceSessions,
  useRevokeMultiSession,
  useSetActiveSession
} from "@better-auth-ui/solid/plugins/multi-session"
import { For, Show } from "solid-js"
import { toast } from "solid-sonner"
import {
  ManageAccountRow,
  ManageAccountRowSkeleton
} from "@/components/auth/multi-session/manage-account"
import { resolveUserLabel } from "@/components/auth/settings/shared/helpers"
import type { DeviceSession } from "@/components/auth/settings/shared/types"
import { Card, CardContent } from "@/components/ui/card"
import { ItemGroup, ItemSeparator } from "@/components/ui/item"
import { cn } from "@/lib/utils"

export type ManageAccountsProps = {
  class?: string
}

export function ManageAccounts(props: ManageAccountsProps = {}) {
  const auth = useAuth<MultiSessionAuthClient>()
  const session = useSession(auth.authClient)
  const multiSessionPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === coreMultiSessionPlugin.id)
  const multiSessionLabels = (): MultiSessionLocalization => ({
    ...multiSessionLocalization,
    ...(multiSessionPluginConfig()?.localization as
      | Partial<MultiSessionLocalization>
      | undefined)
  })
  const deviceSessions = useListDeviceSessions(auth.authClient)
  const setActiveSession = useSetActiveSession(auth.authClient, {
    onSuccess: () => window.scrollTo({ top: 0 })
  })
  const revokeMultiSession = useRevokeMultiSession(auth.authClient, {
    onSuccess: () =>
      toast.success(auth.localization.settings.revokeSessionSuccess)
  })
  const displayName = () =>
    resolveUserLabel(session.data?.user.name, session.data?.user.email)
  const isAccountActionPending = () =>
    setActiveSession.isPending || revokeMultiSession.isPending
  const otherDeviceSessions = () => {
    const sessions = (deviceSessions.data ?? []) as DeviceSession[]

    return sessions.filter(
      (deviceSession) => deviceSession.session.id !== session.data?.session.id
    )
  }

  const switchToSession = (deviceSession: DeviceSession) => {
    setActiveSession.mutate({
      sessionToken: deviceSession.session.token
    } as Parameters<typeof setActiveSession.mutate>[0])
  }

  const signOutSession = (deviceSession: DeviceSession) => {
    revokeMultiSession.mutate({
      sessionToken: deviceSession.session.token
    } as Parameters<typeof revokeMultiSession.mutate>[0])
  }

  return (
    <div class={cn("w-full", props.class)}>
      <h2 class="mb-3 text-sm font-semibold">
        {multiSessionLabels().manageAccounts}
      </h2>
      <Card class="z-card-padding-none">
        <CardContent class="z-card-content-padding-none">
          <ItemGroup class="gap-0">
            <ManageAccountRow
              description={`Signed in as ${displayName()}`}
              image={session.data?.user.image}
              isBusy={isAccountActionPending()}
              isCurrentSession
              name={session.data?.user.name}
              email={session.data?.user.email}
              onSignOut={() => {
                const currentSession = session.data

                if (currentSession) {
                  signOutSession(currentSession as DeviceSession)
                }
              }}
            />

            <For each={otherDeviceSessions()}>
              {(deviceSession) => (
                <>
                  <ItemSeparator />
                  <ManageAccountRow
                    description="Device session"
                    email={deviceSession.user.email}
                    image={deviceSession.user.image}
                    isBusy={isAccountActionPending()}
                    name={deviceSession.user.name}
                    onSignOut={() => signOutSession(deviceSession)}
                    onSwitch={() => switchToSession(deviceSession)}
                  />
                </>
              )}
            </For>

            <Show when={deviceSessions.isPending}>
              <ItemSeparator />
              <ManageAccountRowSkeleton />
            </Show>
          </ItemGroup>
        </CardContent>
      </Card>
    </div>
  )
}

import {
  multiSessionPlugin as coreMultiSessionPlugin,
  type MultiSessionLocalization,
  multiSessionLocalization
} from "@better-auth-ui/core/plugins/multi-session"
import { useAuth, useSession } from "@better-auth-ui/solid"
import { ArrowLeftRight } from "lucide-solid"
import { Show } from "solid-js"
import {
  DropdownMenuSub,
  DropdownMenuSubTrigger
} from "@/components/ui/dropdown-menu"
import { SwitchAccountSubmenuContent } from "./switch-account-submenu-content"

export type SwitchAccountSubmenuProps = {
  class?: string
}

export function SwitchAccountSubmenu(props: SwitchAccountSubmenuProps) {
  const auth = useAuth()
  const session = useSession(auth.authClient, {
    enabled: !import.meta.env.SSR
  })
  const multiSessionPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === coreMultiSessionPlugin.id)
  const multiSessionLabels = (): MultiSessionLocalization => ({
    ...multiSessionLocalization,
    ...(multiSessionPluginConfig()?.localization as
      | Partial<MultiSessionLocalization>
      | undefined)
  })

  return (
    <Show when={session.data}>
      <DropdownMenuSub>
        <DropdownMenuSubTrigger class={props.class}>
          <ArrowLeftRight class="size-4 text-muted-foreground" />
          {multiSessionLabels().switchAccount}
        </DropdownMenuSubTrigger>

        <SwitchAccountSubmenuContent />
      </DropdownMenuSub>
    </Show>
  )
}

import type { MultiSessionAuthClient } from "@better-auth-ui/core/plugins/multi-session"
import {
  multiSessionPlugin as coreMultiSessionPlugin,
  type MultiSessionLocalization,
  multiSessionLocalization
} from "@better-auth-ui/core/plugins/multi-session"
import { useAuth, useSession } from "@better-auth-ui/solid"
import { useListDeviceSessions } from "@better-auth-ui/solid/plugins/multi-session"
import { Link } from "@tanstack/solid-router"
import { Check, CirclePlus } from "lucide-solid"
import { For, Show } from "solid-js"
import type { DeviceSession } from "@/components/auth/settings/shared/types"
import { UserView } from "@/components/auth/user/user-view"
import {
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuSubContent
} from "@/components/ui/dropdown-menu"
import { SwitchAccountSubmenuItem } from "./switch-account-submenu-item"

export function SwitchAccountSubmenuContent() {
  const auth = useAuth<MultiSessionAuthClient>()
  const session = useSession(auth.authClient, {
    enabled: !import.meta.env.SSR
  })
  const multiSessionPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === coreMultiSessionPlugin.id)
  const multiSessionLabels = (): MultiSessionLocalization => ({
    ...multiSessionLocalization,
    ...(multiSessionPluginConfig()?.localization as
      | Partial<MultiSessionLocalization>
      | undefined)
  })
  const deviceSessions = useListDeviceSessions(auth.authClient)
  const otherDeviceSessions = () => {
    const sessions = (deviceSessions.data ?? []) as DeviceSession[]

    return sessions.filter(
      (deviceSession) => deviceSession.session.id !== session.data?.session.id
    )
  }

  return (
    <DropdownMenuSubContent class="min-w-48 max-w-[48svw] md:min-w-56">
      <DropdownMenuItem>
        <UserView
          isPending={deviceSessions.isPending}
          user={session.data?.user}
        />
        <Show when={!deviceSessions.isPending}>
          <Check class="ml-auto size-4" />
        </Show>
      </DropdownMenuItem>

      <For each={otherDeviceSessions()}>
        {(deviceSession) => (
          <SwitchAccountSubmenuItem deviceSession={deviceSession} />
        )}
      </For>

      <DropdownMenuSeparator />

      <DropdownMenuItem class="gap-1.5 rounded-md px-1.5 py-1 text-sm focus:bg-accent focus:text-accent-foreground">
        <Link
          class="flex w-full items-center gap-1.5"
          params={{ path: auth.viewPaths.auth.signIn }}
          to="/auth/$path"
        >
          <CirclePlus class="size-4 text-muted-foreground" />
          {multiSessionLabels().addAccount}
        </Link>
      </DropdownMenuItem>
    </DropdownMenuSubContent>
  )
}

import type { MultiSessionAuthClient } from "@better-auth-ui/core/plugins/multi-session"
import { useAuth } from "@better-auth-ui/solid"
import { useSetActiveSession } from "@better-auth-ui/solid/plugins/multi-session"
import { LoaderCircle } from "lucide-solid"
import type { DeviceSession } from "@/components/auth/settings/shared/types"
import { UserView } from "@/components/auth/user/user-view"
import { DropdownMenuItem } from "@/components/ui/dropdown-menu"

export type SwitchAccountSubmenuItemProps = {
  deviceSession: DeviceSession
}

export function SwitchAccountSubmenuItem(props: SwitchAccountSubmenuItemProps) {
  const auth = useAuth<MultiSessionAuthClient>()
  const setActiveSession = useSetActiveSession(auth.authClient, {
    onSuccess: () => window.scrollTo({ top: 0 })
  })

  return (
    <DropdownMenuItem
      disabled={setActiveSession.isPending}
      onSelect={() => {
        setActiveSession.mutate({
          sessionToken: props.deviceSession.session.token
        } as Parameters<typeof setActiveSession.mutate>[0])
      }}
    >
      <UserView user={props.deviceSession.user} />
      {setActiveSession.isPending ? (
        <LoaderCircle class="ml-auto size-4 animate-spin" />
      ) : null}
    </DropdownMenuItem>
  )
}

export function hasAuthPlugin(plugins: { id: string }[], id: string) {
  return plugins.some((plugin) => plugin.id === id)
}

export const resolveUserLabel = (name?: string | null, email?: string | null) =>
  name?.trim() || email?.trim() || "Signed in user"

export const resolveUserInitials = (
  name?: string | null,
  email?: string | null
) => resolveUserLabel(name, email).slice(0, 2).toUpperCase()

export function timeAgo(date: Date | string) {
  const createdAt = date instanceof Date ? date : new Date(date)
  const seconds = Math.floor((Date.now() - createdAt.getTime()) / 1000)
  const relativeTimeFormat = new Intl.RelativeTimeFormat(undefined, {
    numeric: "auto"
  })

  const units: [Intl.RelativeTimeFormatUnit, number][] = [
    ["year", 31_536_000],
    ["month", 2_592_000],
    ["week", 604_800],
    ["day", 86_400],
    ["hour", 3_600],
    ["minute", 60],
    ["second", 1]
  ]

  for (const [unit, threshold] of units) {
    if (seconds >= threshold) {
      return relativeTimeFormat.format(-Math.floor(seconds / threshold), unit)
    }
  }

  return relativeTimeFormat.format(0, "second")
}

import type { getProviderName, SettingsView } from "@better-auth-ui/core"
import type { ApiKeyAuthClient } from "@better-auth-ui/core/plugins/api-key"
import type { deleteUserLocalization } from "@better-auth-ui/core/plugins/delete-user"
import type { MultiSessionAuthClient } from "@better-auth-ui/core/plugins/multi-session"
import type { ListApiKeysData } from "@better-auth-ui/solid/plugins/api-key"
